const formatDisplayTime = (time) => {
  if (!time) return "Select a session";
  const [hours, minutes] = time.split(":").map(Number);
  const suffix = hours >= 12 ? "PM" : "AM";
  const hour12 = hours % 12 || 12;
  return `${hour12}:${String(minutes).padStart(2, "0")} ${suffix}`;
};

function SectionCard({ title, subtitle, children }) {
  return (
    <div className="card cardPad" style={{ display: "grid", gap: "18px" }}>
      <div>
        <div className="sectionTitle">{title}</div>
        <div className="sub">{subtitle}</div>
      </div>
      {children}
    </div>
  );
}

function SummaryTile({ label, value, inverse = false }) {
  return (
    <div
      style={{
        border: inverse ? "1px solid rgba(255,255,255,0.16)" : "1px solid var(--border)",
        borderRadius: "16px",
        padding: "16px",
        background: inverse ? "rgba(255,255,255,0.12)" : "rgba(255,255,255,0.72)",
        display: "grid",
        gap: "6px",
      }}
    >
      <div
        style={{
          fontSize: "12px",
          fontWeight: 700,
          letterSpacing: "0.06em",
          textTransform: "uppercase",
          color: inverse ? "rgba(255,255,255,0.74)" : "var(--text-muted)",
        }}
      >
        {label}
      </div>
      <div style={{ fontSize: "20px", fontWeight: 700, color: inverse ? "#fff" : "var(--text)" }}>{value}</div>
    </div>
  );
}

export default function CustomerAppointmentForm({
  title,
  subtitle,
  modeLabel,
  vehicleField,
  date,
  setDate,
  minDate,
  availableSlots,
  loading,
  error,
  time,
  setTime,
  submit,
  savingLabel,
  submitLabel,
  cancelLabel,
  onCancel,
  selectedVehicleLabel,
}) {
  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">{title}</div>
          <div className="pageSub">{subtitle}</div>
        </div>
      </div>

      <div style={{ display: "grid", gap: "20px", maxWidth: "920px", margin: "0 auto" }}>
        <div
          className="card cardPad"
          style={{
            display: "grid",
            gap: "16px",
            background: "linear-gradient(135deg, rgba(12,58,87,0.96) 0%, rgba(17,73,109,0.95) 62%, rgba(141,187,1,0.92) 100%)",
            color: "#fff",
          }}
        >
          <div style={{ display: "flex", justifyContent: "space-between", gap: "16px", alignItems: "center", flexWrap: "wrap" }}>
            <div>
              <div style={{ fontSize: "12px", textTransform: "uppercase", letterSpacing: "0.14em", opacity: 0.72 }}>{modeLabel}</div>
              <div style={{ fontSize: "28px", fontWeight: 800, letterSpacing: "-0.04em", marginTop: "8px" }}>
                {selectedVehicleLabel || "Showroom visit"}
              </div>
              <div style={{ marginTop: "6px", opacity: 0.82 }}>Customer booking experience in the Leaf Lanka premium style.</div>
            </div>
            <span className="badge" style={{ background: "rgba(255,255,255,0.14)", color: "#fff", borderColor: "rgba(255,255,255,0.18)" }}>
              9 AM - 5 PM
            </span>
          </div>

          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))", gap: "14px" }}>
            <SummaryTile label="Date" value={date || "Select date"} inverse />
            <SummaryTile label="Session" value={formatDisplayTime(time)} inverse />
            <SummaryTile label="Policy" value="Future bookings only" inverse />
          </div>
        </div>

        <form onSubmit={submit} style={{ display: "grid", gap: "20px" }}>
          {vehicleField ? (
            <SectionCard title="Vehicle" subtitle="Choose the vehicle you want to view or test drive.">
              {vehicleField}
            </SectionCard>
          ) : null}

          <SectionCard title="Schedule" subtitle="Select a future date and then choose one available hourly session.">
            <div style={{ display: "grid", gap: "16px" }}>
              <div>
                <label className="label">Appointment Date</label>
                <input type="date" required value={date} onChange={(event) => setDate(event.target.value)} min={minDate} className="input" />
                <div className="sub" style={{ marginTop: "8px" }}>
                  Sessions are available from 9:00 AM to 5:00 PM on open days only.
                </div>
              </div>

              {error ? (
                <div
                  className="card cardPad"
                  style={{ borderColor: "rgba(186, 94, 94, 0.25)", color: "var(--danger)", background: "rgba(255,255,255,0.94)" }}
                >
                  {error}
                </div>
              ) : null}

              <div>
                <label className="label">Available Sessions</label>
                {loading ? (
                  <div className="card cardPad" style={{ color: "var(--text-muted)" }}>
                    Loading available sessions...
                  </div>
                ) : date ? (
                  availableSlots.length > 0 ? (
                    <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(160px, 1fr))", gap: "12px", marginTop: "10px" }}>
                      {availableSlots.map((slot) => {
                        const selected = time === slot.time;
                        const disabled = slot.availableStaffCount === 0;

                        return (
                          <button
                            key={slot.time}
                            type="button"
                            onClick={() => !disabled && setTime(slot.time)}
                            className="btn"
                            disabled={disabled}
                            style={{
                              padding: "14px 12px",
                              borderRadius: "18px",
                              background: selected ? "linear-gradient(135deg, #0C3A57 0%, #15517a 58%, #8DBB01 100%)" : "rgba(255,255,255,0.92)",
                              color: selected ? "#fff" : "var(--navy)",
                              border: selected ? "1px solid transparent" : "1px solid var(--border)",
                              opacity: disabled ? 0.45 : 1,
                              cursor: disabled ? "not-allowed" : "pointer",
                              minHeight: "78px",
                              display: "grid",
                              gap: "4px",
                            }}
                            title={`${slot.availableStaffCount} staff member${slot.availableStaffCount !== 1 ? "s" : ""} available`}
                          >
                            <div style={{ fontWeight: 700 }}>{formatDisplayTime(slot.time)}</div>
                            <div style={{ fontSize: "12px" }}>{slot.availableStaffCount} available</div>
                          </button>
                        );
                      })}
                    </div>
                  ) : null
                ) : (
                  <div className="card cardPad" style={{ color: "var(--text-muted)" }}>
                    Select a date to see available sessions.
                  </div>
                )}
              </div>
            </div>
          </SectionCard>

          <div
            className="card cardPad"
            style={{
              display: "grid",
              gap: "8px",
              background: "rgba(255,255,255,0.86)",
            }}
          >
            <div className="sectionTitle" style={{ fontSize: "16px" }}>Booking Summary</div>
            <div style={{ color: "var(--text-secondary)", lineHeight: 1.65 }}>
              Selected session: <strong style={{ color: "var(--navy)" }}>{formatDisplayTime(time)}</strong>
            </div>
          </div>

          <div style={{ display: "flex", gap: "12px", flexWrap: "wrap", justifyContent: "flex-end" }}>
            <button type="button" onClick={onCancel} className="btn" style={{ minWidth: "160px" }}>
              {cancelLabel}
            </button>
            <button type="submit" disabled={!date || !time} className="btn btnPrimary" style={{ minWidth: "200px" }}>
              {savingLabel || submitLabel}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export { formatDisplayTime };
